import React from "react";

function CatererCard({ caterer, onDelete }) {
  return (
    <div style={{ border: "1px solid #ccc", padding: 10, margin: 10 }}>
      <h2>{caterer.name}</h2>
      <p>{caterer.location}</p>
      <p>₹{caterer.pricePerPlate}</p>
      <p>{caterer.cuisines.join(", ")}</p>
      <p>⭐ {caterer.rating}</p>

      <button onClick={() => onDelete(caterer.id)}>Delete</button>
    </div>
  );
}

export default CatererCard;
